  inset: 0;
  z-index: 999;
  background: transparent;
}

.protocols-menu {
  position: fixed;
  z-index: 1000;
  min-width: 340px;
  max-width: 480px;
  max-height: 65vh;
  overflow-y: auto;
  background: #0f1520;
  border: 1px solid rgba(125, 211, 252, 0.25);
  border-radius: 10px;
  box-shadow: 0 12px 40px rgba(0, 0, 0, 0.6), 0 0 20px rgba(125, 211, 252, 0.08);
  padding: 6px;
  display: flex;
  flex-direction: column;
  gap: 2px;
  animation: protocols-menu-pop 120ms cubic-bezier(0.16, 1, 0.3, 1);
}

@keyframes protocols-menu-pop {
  from { opacity: 0; transform: translateY(-8px); }
  to { opacity: 1; transform: translateY(0); }
}

.protocols-menu::-webkit-scrollbar {
  width: 8px;
}

.protocols-menu::-webkit-scrollbar-track {
  background: transparent;
}

.protocols-menu::-webkit-scrollbar-thumb {
  background: #1f2937;
  border-radius: 4px;
}

.protocols-menu::-webkit-scrollbar-thumb:hover {
  background: #374151;
}

.protocols-menu-section-label {
  padding: 8px 12px 4px 12px;
  font-family: "JetBrains Mono", "SF Mono", Menlo, monospace;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: #6b7280;
  margin-top: 4px;
}

.protocols-menu-section-label:first-child {
  margin-top: 0;
}

.protocols-menu-divider {
  height: 1px;
  background: #1f2937;
  margin: 4px 0;
}

