  display: flex;
  flex-direction: column;
  gap: 4px;
  padding: 10px 12px;
  border-radius: 8px;
  border: 1px solid transparent;
  background: transparent;
  cursor: pointer;
  transition: all 120ms ease;
}

.protocols-menu-item:hover {
  background: rgba(125, 211, 252, 0.08);
