}

.protocols-menu-item.disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

.protocols-menu-item.disabled:hover {
  background: transparent;
  border-color: transparent;
}

.protocols-menu-item-header {
  display: flex;
  align-items: center;
  gap: 8px;
}

.protocols-menu-icon {
  font-size: 18px;
  line-height: 1;
  flex: 0 0 auto;
}

.protocols-menu-item-name {
  font-size: 13px;
  font-weight: 600;
  color: #f3f4f6;
  line-height: 1.2;
}

.protocols-menu-item-desc {
  font-size: 11px;
  color: #9ca3af;
  line-height: 1.4;
  margin-left: 26px;
}

.protocols-menu-item-footer {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
  margin-left: 26px;
}

.protocols-menu-badge {
  display: inline-flex;
  align-items: center;
  font-size: 9px;
  font-weight: 600;
  letter-spacing: 0.04em;
  padding: 2px 6px;
  border-radius: 4px;
  background: rgba(125, 211, 252, 0.12);
  color: #7dd3fc;
  border: 1px solid rgba(125, 211, 252, 0.2);
